  CONSTRAINT `student_groups_course_id_foreign` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`),
  CONSTRAINT `student_groups_session_id_foreign` FOREIGN KEY (`session_id`) REFERENCES `sessions` (`id`)
